INSERT INTO settings (key, value, data_type, description, is_editable) VALUES ('demo_services_json', '[{"id": "demo-printing-services", "slug": "printing", "name_en": "Printing Services", "name_bn": "প্রিন্টিং সেবা", "short_description_en": "Business cards, banners, brochures & large format printing.", "short_description_bn": "বিজনেস কার্ড, ব্যানার, ব্রোশিওর ও লার্জ ফরম্যাট প্রিন্টিং।", "category": "printing", "pricing_type": "fixed", "base_price": 500, "is_featured": true, "icon_color": "#1e5ba8", "featured_image_url": "https://placehold.co/1920x1080/webp?text=Printing%20Services"}, {"id": "demo-legal-assistance", "slug": "legal", "name_en": "Legal Assistance", "name_bn": "আইনি সহায়তা", "short_description_en": "Government documents, affidavits & legal filings.", "short_description_bn": "সরকারি ডকুমেন্ট, শপথপত্র ও আইনি কাজ।", "category": "legal", "pricing_type": "custom_quote", "min_price": 1000, "is_featured": true, "icon_color": "#f59e0b", "featured_image_url": "https://placehold.co/1920x1080/webp?text=Legal%20Assistance"}, {"id": "demo-software-development", "slug": "software", "name_en": "Software Development", "name_bn": "সফটওয়্যার ডেভেলপমেন্ট", "short_description_en": "Custom web, mobile & enterprise software solutions.", "short_description_bn": "কাস্টম ওয়েব, মোবাইল ও এন্টারপ্রাইজ সফটওয়্যার সমাধান।", "category": "software", "pricing_type": "custom_quote", "min_price": 25000, "is_featured": true, "icon_color": "#16a34a", "featured_image_url": "https://placehold.co/1920x1080/webp?text=Software%20Development"}, {"id": "demo-web-design", "slug": "web-design", "name_en": "Website Design", "name_bn": "ওয়েবসাইট ডিজাইন", "short_description_en": "Modern responsive websites with SEO optimization.", "short_description_bn": "SEO অপ্টিমাইজড আধুনিক রেসপন্সিভ ওয়েবসাইট।", "category": "software", "pricing_type": "package", "base_price": 15000, "is_featured": false, "icon_color": "#7c3aed", "featured_image_url": "https://placehold.co/1920x1080/webp?text=Website%20Design"}